import{_ as a,a as d,b as e,c as o,d as r,e as l,f as i}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as s,o as n,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const q=JSON.parse('{"title":"Discord 渠道添加说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/upload/discord.md","filePath":"cn/upload/discord.md","lastUpdated":1781962217000}'),p={name:"cn/upload/discord.md"};function b(u,t,D,m,_,g){return n(),c("div",null,[...t[0]||(t[0]=[h('<h1 id="discord-渠道添加说明" tabindex="-1">Discord 渠道添加说明 <a class="header-anchor" href="#discord-渠道添加说明" aria-label="Permalink to &quot;Discord 渠道添加说明&quot;">​</a></h1><h2 id="添加前要准备什么" tabindex="-1">添加前要准备什么 <a class="header-anchor" href="#添加前要准备什么" aria-label="Permalink to &quot;添加前要准备什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>需要准备</th><th>用途</th></tr></thead><tbody><tr><td>Discord 账号</td><td>用于创建服务器、频道和开发者应用。</td></tr><tr><td>一个 Discord 服务器</td><td>机器人需要先加入服务器，再访问指定频道。</td></tr><tr><td>一个文字频道</td><td>图片和文件最终会发送到这个频道。</td></tr><tr><td>Discord Developer Portal</td><td>用于创建应用、机器人并获取 <code>Bot Token</code>。</td></tr></tbody></table><h2 id="入口位置" tabindex="-1">入口位置 <a class="header-anchor" href="#入口位置" aria-label="Permalink to &quot;入口位置&quot;">​</a></h2><ol><li>进入系统配置。</li><li>打开上传设置。</li><li>点击右上角“添加渠道”。</li><li>选择 <code>Discord</code>。</li></ol><h2 id="字段说明" tabindex="-1">字段说明 <a class="header-anchor" href="#字段说明" aria-label="Permalink to &quot;字段说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>作用</th><th>是否必填</th></tr></thead><tbody><tr><td>渠道名称</td><td>用于区分当前渠道，例如“Discord 主频道”。</td><td>必填</td></tr><tr><td>Bot Token</td><td>Discord 机器人令牌。</td><td>必填</td></tr><tr><td>Channel ID</td><td>目标文字频道的 ID。</td><td>必填</td></tr><tr><td>代理地址（可选）</td><td>仅在访问 Discord CDN 不稳定时使用，请填写完整代理地址（包含 <code>https://</code>）。</td><td>选填</td></tr></tbody></table><h2 id="配置步骤" tabindex="-1">配置步骤 <a class="header-anchor" href="#配置步骤" aria-label="Permalink to &quot;配置步骤&quot;">​</a></h2><h3 id="_1-创建-discord-服务器和文字频道" tabindex="-1">1. 创建 Discord 服务器和文字频道 <a class="header-anchor" href="#_1-创建-discord-服务器和文字频道" aria-label="Permalink to &quot;1. 创建 Discord 服务器和文字频道&quot;">​</a></h3><ol><li>打开 Discord。</li><li>创建一个新的服务器，或者使用你自己的现有服务器。</li><li>在服务器中创建一个频道。</li></ol><p><img src="'+a+'" alt="创建服务器" loading="lazy"></p><h3 id="_2-在-discord-developer-portal-创建机器人" tabindex="-1">2. 在 Discord Developer Portal 创建机器人 <a class="header-anchor" href="#_2-在-discord-developer-portal-创建机器人" aria-label="Permalink to &quot;2. 在 Discord Developer Portal 创建机器人&quot;">​</a></h3><ol><li>打开 Discord Developer Portal：<code>https://discord.com/developers/applications</code></li><li>点击 <code>New Application</code>。</li><li>输入应用名称并完成创建。</li><li>在左侧进入 <code>Bot</code> 页面。</li><li>在 <code>Bot</code> 页面生成或重置 Token。</li><li>保存这串机器人令牌。</li></ol><p>这串令牌就是系统配置中需要填写的 <code>Bot Token</code>。</p><p><img src="'+d+'" alt="查看机器人令牌" loading="lazy"></p><h3 id="_3-在-oauth2-页面生成授权链接并安装机器人" tabindex="-1">3. 在 OAuth2 页面生成授权链接并安装机器人 <a class="header-anchor" href="#_3-在-oauth2-页面生成授权链接并安装机器人" aria-label="Permalink to &quot;3. 在 OAuth2 页面生成授权链接并安装机器人&quot;">​</a></h3><ol><li>打开左侧 <code>OAuth2</code> 页面。</li><li>在 <code>范围</code> 中勾选 <code>机器人</code>。</li><li>在权限区域勾选下面这 4 项：</li></ol><table tabindex="0"><thead><tr><th>权限</th><th>是否需要</th></tr></thead><tbody><tr><td>查看频道</td><td>需要</td></tr><tr><td>发送消息</td><td>需要</td></tr><tr><td>添加文件</td><td>需要</td></tr><tr><td>读取消息历史记录</td><td>需要</td></tr></tbody></table><ol start="4"><li>在页面下方确认 <code>集成类型</code> 为 <code>服务器安装</code>。</li><li>复制底部 <code>已生成的URL</code>。</li><li>打开这个 URL。</li><li>选择你要安装的目标服务器。</li><li>完成授权安装。</li></ol><p><img src="'+e+'" alt="在oa2勾选机器人权限" loading="lazy"></p><p><img src="'+o+'" alt="邀请机器人到频道" loading="lazy"></p><h3 id="_4-开启开发者模式并复制-channel-id" tabindex="-1">4. 开启开发者模式并复制 Channel ID <a class="header-anchor" href="#_4-开启开发者模式并复制-channel-id" aria-label="Permalink to &quot;4. 开启开发者模式并复制 Channel ID&quot;">​</a></h3><ol><li>点击 Discord 左下角头像旁边的齿轮，进入“用户设置”。</li><li>在左侧找到“高级”。</li><li>打开“开发者模式”。</li><li>回到目标文字频道。</li><li>右键频道名称。</li><li>点击“复制频道 ID”。</li></ol><p>复制出来的这一串数字，就是系统配置中需要填写的 <code>Channel ID</code>。</p><p><img src="'+r+'" alt="开启开发者权限" loading="lazy"></p><p><img src="'+l+'" alt="复制群频道id" loading="lazy"></p><h3 id="_5-在系统中填写-discord-渠道" tabindex="-1">5. 在系统中填写 Discord 渠道 <a class="header-anchor" href="#_5-在系统中填写-discord-渠道" aria-label="Permalink to &quot;5. 在系统中填写 Discord 渠道&quot;">​</a></h3><p>回到系统配置弹窗后，按下表填写：</p><table tabindex="0"><thead><tr><th>页面字段</th><th>填写内容</th></tr></thead><tbody><tr><td>渠道名称</td><td>自定义渠道名称，例如 <code>Discord主频道</code></td></tr><tr><td>Bot Token</td><td>在 Discord Developer Portal 的 <code>Bot</code> 页面保存的令牌</td></tr><tr><td>Channel ID</td><td>刚才复制的频道 ID</td></tr><tr><td>代理地址（可选）</td><td>按需填写，格式例如 <code>https://your-proxy.example.com</code></td></tr></tbody></table><p>填写完成后点击保存。</p><p><img src="'+i+`" alt="添加dc新渠道配置" loading="lazy"></p><h2 id="添加完成后怎么检查" tabindex="-1">添加完成后怎么检查 <a class="header-anchor" href="#添加完成后怎么检查" aria-label="Permalink to &quot;添加完成后怎么检查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>检查项</th><th>检查方式</th></tr></thead><tbody><tr><td>渠道卡片是否出现</td><td>保存后，上传设置页面应显示 Discord 渠道卡片。</td></tr><tr><td>渠道是否能启用</td><td>开关应可正常开启。</td></tr><tr><td>配置信息是否已保存</td><td>详情页应能看到 Bot Token 和 Channel ID 已写入。</td></tr><tr><td>上传是否正常</td><td>上传一张测试图片，确认图片已进入目标 Discord 文字频道。</td></tr></tbody></table><h2 id="一句话流程速查" tabindex="-1">一句话流程速查 <a class="header-anchor" href="#一句话流程速查" aria-label="Permalink to &quot;一句话流程速查&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建 Discord 服务器</span></span>
<span class="line"><span>-&gt; 创建一个文字频道</span></span>
<span class="line"><span>-&gt; 去 Discord Developer Portal 创建机器人</span></span>
<span class="line"><span>-&gt; 在 Bot 页面保存 Bot Token</span></span>
<span class="line"><span>-&gt; 在 OAuth2 页面勾选 机器人、查看频道、发送消息、添加文件、读取消息历史记录</span></span>
<span class="line"><span>-&gt; 复制生成的 URL 并授权安装到目标服务器</span></span>
<span class="line"><span>-&gt; 给目标文字频道放开相同权限</span></span>
<span class="line"><span>-&gt; 开启开发者模式</span></span>
<span class="line"><span>-&gt; 右键目标文字频道复制 Channel ID</span></span>
<span class="line"><span>-&gt; 回系统配置填写 Bot Token 和 Channel ID</span></span>
<span class="line"><span>-&gt; 保存后上传测试图片</span></span></code></pre></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ol><li>Discord Developers Getting Started：<a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord 官方帮助：如何查找频道 ID：<a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const x=s(p,[["render",b]]);export{q as __pageData,x as default};
